                rates["CHF"] = {"usd": 1.14, "eur": 1.04, "cad": 1.55, "gbp": 0.90, "jpy": 170.45, "chf": 1, "aud": 1.73, "cny": 8.25}
                rates["AUD"] = {"usd": 0.66, "eur": 0.60, "cad": 0.89, "gbp": 0.52, "jpy": 98.04, "chf": 0.58, "aud": 1, "cny": 4.76}
